          spellcheck="false" autocorrect="off" autocapitalize="off"></textarea>
      </div>
      <div class="form-group">
        <label class="form-label" for="decryptKey">
          <span class="label-icon">🔐</span> Decrypt with (My Key)
        </label>
        <select class="form-select" id="decryptKey"></select>
      </div>
      <div class="form-group">
        <label class="form-label" for="decryptPassphrase">Passphrase</label>
        <div class="input-group">
          <input type="password" class="form-input" id="decryptPassphrase"
            placeholder="Your key's passphrase" autocomplete="off" autocorrect="off">
          <button class="input-reveal" data-target="decryptPassphrase" type="button" aria-label="Toggle visibility">
            <svg width="18" height="18" viewBox="0 0 18 18" fill="none"><ellipse cx="9" cy="9" rx="7" ry="5" stroke="currentColor" stroke-width="1.5"/><circle cx="9" cy="9" r="2.5" stroke="currentColor" stroke-width="1.5"/></svg>
          </button>
        </div>
      </div>
      <button class="btn btn-primary btn-full" id="btnDecrypt">
        <svg width="14" height="14" viewBox="0 0 14 14" fill="none"><rect x="2" y="6" width="10" height="7" rx="1.5" stroke="currentColor" stroke-width="1.5"/><path d="M4.5 6V4.5a2.5 2.5 0 0 1 5 0" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-dasharray="2 1.5"/></svg>
        Decrypt &amp; Verify
      </button>
      <div id="sigStatusBanner" class="sig-status-banner" style="display:none" role="status"></div>
      <div class="output-area" id="decryptOutput">
        <div class="output-header">
          <span class="output-label">Decrypted message</span>
          <button class="copy-btn" id="btnCopyDecrypt">
            <svg width="12" height="12" viewBox="0 0 12 12" fill="none"><rect x="4" y="4" width="7" height="7" rx="1.5" stroke="currentColor" stroke-width="1.2"/><path d="M2 8V2.5A.5.5 0 0 1 2.5 2H8" stroke="currentColor" stroke-width="1.2" stroke-linecap="round"/></svg>
            Copy
          </button>
        </div>
        <div class="output-box" id="decryptResult"></div>
      </div>
    </div>
  </main>
</div>
<div id="modalOverlay" class="modal-overlay" role="dialog" aria-modal="true">
  <div class="modal" id="modalContent">
    <div class="modal-drag"></div>
    <div id="modalBody"></div>
  </div>
</div>
<div class="loading-overlay" id="loadingOverlay">
  <div class="loading-ring"></div>
  <div class="loading-text" id="loadingText">Working…</div>
</div>
<div id="toast-container" aria-live="polite"></div>
<div id="legalOverlay" class="legal-overlay" role="dialog" aria-modal="true" aria-label="Legal information">
  <div class="legal-sheet" id="legalSheet">
    <div class="legal-drag-handle"></div>
    <div class="legal-scroll-area" id="legalScrollArea">
